            acc.x = fmaf(aval, tv.x, acc.x);
            acc.y = fmaf(aval, tv.y, acc.y);
            acc.z = fmaf(aval, tv.z, acc.z);
            acc.w = fmaf(aval, tv.w, acc.w);
        }
        float4 yv = *reinterpret_cast<float4*>(y + row * d + col);
        yv.x += acc.x;
        yv.y += acc.y;
        yv.z += acc.z;
